class PlanBodyScreen(ModalScreen):
    """Modal screen displaying the full plan text fetched on-demand."""

    BINDINGS = [
        Binding("escape", "dismiss", "Close"),
        Binding("q", "dismiss", "Close"),
        Binding("space", "dismiss", "Close"),
    ]

    DEFAULT_CSS = """
    PlanBodyScreen {
        align: center middle;
    }

    #body-dialog {
        width: 90%;
        max-width: 120;
        height: 80%;
        background: $surface;
        border: solid $primary;
        padding: 1 2;
    }

    #body-header {
        width: 100%;
        height: auto;
        margin-bottom: 1;
    }

    #body-plan-number {
        text-style: bold;
        color: $primary;
    }

    #body-title {
        color: $text;
    }

    #body-divider {
        height: 1;
        background: $primary-darken-2;
        margin-bottom: 1;
    }

    #body-content-container {
        height: 1fr;
        overflow-y: auto;
    }

    #body-content {
        width: 100%;
    }

    #body-footer {
        text-align: center;
        margin-top: 1;
        color: $text-muted;
    }

    #body-empty {
        color: $text-muted;
        text-style: italic;
    }

    #body-loading {
        color: $text-muted;
        text-style: italic;
    }

    #body-error {
        color: $error;
        text-style: italic;
    }
    """

    def __init__(
        self,
        *,
        provider: PlanDataProvider,
        plan_id: int,
        plan_body: str,
        full_title: str,
        content_type: Literal["Plan", "Objective"],
    ) -> None:
        """Initialize with plan metadata and provider for async loading.

        Args:
            provider: Data provider for fetching plan/objective content
            plan_id: The plan identifier
            plan_body: The plan body (contains metadata with comment ID)
            full_title: The full plan/objective title for display
            content_type: Display label - "Plan" or "Objective"
        """
        super().__init__()
        self._provider = provider
        self._plan_id = plan_id
        self._plan_body = plan_body
        self._full_title = full_title
        self._content_type = content_type
        self._content: str | None = None
        self._error: str | None = None
        self._loading = True

    def compose(self) -> ComposeResult:
        """Create the issue body dialog content."""
        label = self._content_type.lower()
        with Vertical(id="body-dialog"):
            # Header: Plan/Objective number + title
            with Vertical(id="body-header"):
                yield Label(f"{self._content_type} #{self._plan_id}", id="body-plan-number")
                yield Label(self._full_title, id="body-title", markup=False)

            # Divider
            yield Label("", id="body-divider")

            # Body content in scrollable container - starts with loading state
            with Container(id="body-content-container"):
                yield Label(f"Loading {label} content...", id="body-loading")

            yield Label("Press Esc, q, or Space to close", id="body-footer")

    def on_mount(self) -> None:
        """Fetch plan content when screen mounts."""
        self._fetch_content()

    @work(thread=True)
    def _fetch_content(self) -> None:
        """Fetch plan/objective content in background thread."""
        content: str | None = None
        error: str | None = None

        # Error boundary: catch all exceptions from HTTP operations to display
        # them in the UI rather than crashing the TUI.
        try:
            if self._content_type == "Objective":
                content = self._provider.fetch_objective_content(self._plan_id, self._plan_body)
            else:
                content = self._provider.fetch_plan_content(self._plan_id, self._plan_body)
        except Exception as e:
            error = str(e)

        # Update UI on main thread
        self.app.call_from_thread(self._on_content_loaded, content, error)

    def _on_content_loaded(self, content: str | None, error: str | None) -> None:
        """Handle content loaded - update the display.

        Args:
            content: The fetched plan content, or None if not found
            error: Error message if fetch failed, or None
        """
        self._loading = False
        self._content = content
        self._error = error

        # Get the container and replace its content
        container = self.query_one("#body-content-container", Container)

        # Remove the loading label
        loading_label = container.query_one("#body-loading", Label)
        loading_label.remove()

        # Add the appropriate content
        if error is not None:
            container.mount(Label(f"Error: {error}", id="body-error"))
        elif content:
            container.mount(Markdown(content, id="body-content"))
        else:
            label = self._content_type.lower()
            container.mount(Label(f"(No {label} content found)", id="body-empty"))

def action_view_comments(self) -> None:
    """Display unresolved PR review comments in a modal."""
    row = self._get_selected_row()
    if row is None:
        return
    if row.pr_number is None:
        if self._status_bar is not None:
            self._status_bar.set_message("No PR linked to this plan")
        return
    unresolved = row.total_comment_count - row.resolved_comment_count
    if unresolved == 0:
        if self._status_bar is not None:
            self._status_bar.set_message("No unresolved comments")
        return
    self.push_screen(
        UnresolvedCommentsScreen(
            provider=self._provider,
            pr_number=row.pr_number,
            full_title=row.full_title,
            resolved_count=row.resolved_comment_count,
            total_count=row.total_comment_count,
        )
    )

def action_cursor_down(self) -> None:
    """Move cursor down (vim j key)."""
    if self._table is not None:
        self._table.action_cursor_down()

def action_cursor_up(self) -> None:
    """Move cursor up (vim k key)."""
    if self._table is not None:
        self._table.action_cursor_up()

def action_start_filter(self) -> None:
    """Activate filter mode and focus the input."""
    if self._filter_input is None:
        return
    self._filter_state = self._filter_state.activate()
    self._filter_input.disabled = False
    self._filter_input.add_class("visible")
    self._filter_input.focus()

def _apply_filter(self) -> None:
    """Apply current filter query to the table."""
    self._rows = self._apply_filter_and_sort(self._all_rows)

    if self._table is not None:
        self._table.populate(self._rows)

        if success:
            self._status_bar.set_message(f"Copied: {cmd}")
        else:
            self._status_bar.set_message(f"Clipboard unavailable. Copy manually: {cmd}")

def _get_selected_row(self) -> PlanRowData | None:
    """Get currently selected row data."""
    if self._table is None:
        return None
    return self._table.get_selected_row_data()

def execute_palette_command(self, command_id: str) -> None:
    """Execute a command from the palette on the selected row.

    Args:
        command_id: The ID of the command to execute
    """
    row = self._get_selected_row()
    if row is None:
        return

    if command_id == "open_browser":
        url = row.pr_url or row.plan_url
        if url:
            self._provider.browser.launch(url)
            self.notify(f"Opened {url}")

    elif command_id == "open_issue":
        if row.plan_url:
            self._provider.browser.launch(row.plan_url)

